import sys

class Solution:
    def longestCommonPrefix(self, strs: list[str]) -> str:
        if not strs:
            return "-1"
        # Start with the first string as candidate
        prefix = strs[0]
        for s in strs[1:]:
            # Reduce prefix until it matches the start of s
            while not s.startswith(prefix):
                prefix = prefix[:-1]
                if not prefix:
                    return "-1"
        return prefix if prefix else "-1"

