#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string longestCommonPrefix(vector<string>& strs) {
        if (strs.empty()) return "-1";
        string prefix = strs[0];
        for (size_t i = 1; i < strs.size(); ++i) {
            const string& s = strs[i];
            while (s.rfind(prefix, 0) != 0) { // prefix not at start
                if (prefix.empty()) return "-1";
                prefix.pop_back();
            }
            if (prefix.empty()) return "-1";
        }
        return prefix.empty() ? string("-1") : prefix;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<string> strs;
    strs.reserve(n);
    string s;
    for (int i = 0; i < n; ++i) {
        if (!(cin >> s)) s = "";
        strs.push_back(s);
    }
    Solution sol;
    string ans = sol.longestCommonPrefix(strs);
    cout << ans << "\n";
    return 0;
}
